/**
 * Analytics data models for the dashboard feature.
 *
 * These types define the shape of analytics data returned by the
 * AnalyticsService. They are designed to be serializable to JSON
 * for a future HTTP API layer.
 */

import type { OrderStatus } from './order.js';

/**
 * Granularity for time-series aggregations.
 */
export type TimeGranularity = 'hour' | 'day' | 'week' | 'month';

/**
 * Metric types available for querying.
 */
export type MetricType = 'revenue' | 'orders' | 'users' | 'average-order-value';

/**
 * A single point in a time-series dataset.
 */
export interface TimeSeriesPoint {
  /** ISO 8601 timestamp for the start of this bucket */
  timestamp: string;
  /** Aggregated value for this time bucket */
  value: number;
}

/**
 * Time-series dataset with metadata.
 */
export interface TimeSeriesData {
  metric: MetricType;
  granularity: TimeGranularity;
  start: string;
  end: string;
  points: TimeSeriesPoint[];
}

/**
 * Summary of a single metric (for dashboard cards).
 */
export interface MetricSummary {
  metric: MetricType;
  /** Current value for the selected period */
  currentValue: number;
  /** Value for the previous period (for comparison) */
  previousValue: number;
  /** Percentage change from previous to current */
  changePercent: number;
}

/**
 * Breakdown of orders by status.
 */
export interface OrderStatusBreakdown {
  status: OrderStatus;
  count: number;
  total: number;
}

/**
 * Top-performing entity (user, product, etc.).
 */
export interface TopEntity {
  id: string;
  name: string;
  value: number;
}

/**
 * Full dashboard response combining all analytics widgets.
 */
export interface DashboardData {
  /** Summary metrics (revenue, orders, users, AOV) */
  metrics: MetricSummary[];
  /** Revenue over time for the chart */
  revenueTimeSeries: TimeSeriesData;
  /** Orders over time for the chart */
  ordersTimeSeries: TimeSeriesData;
  /** Order count/value breakdown by status */
  ordersByStatus: OrderStatusBreakdown[];
  /** Top customers by revenue */
  topCustomers: TopEntity[];
  /** Generated at timestamp */
  generatedAt: string;
}

/**
 * Query parameters for filtering analytics data.
 */
export interface AnalyticsQuery {
  /** Start of the date range (ISO 8601) */
  startDate: string;
  /** End of the date range (ISO 8601) */
  endDate: string;
  /** Time bucket granularity (defaults to 'day') */
  granularity?: TimeGranularity;
  /** Filter to a specific user */
  userId?: string;
}

/**
 * Query parameters for a single metric endpoint.
 */
export interface MetricQuery {
  metric: MetricType;
  startDate: string;
  endDate: string;
  granularity?: TimeGranularity;
  userId?: string;
}

/**
 * Analytics service — aggregates order and user data into dashboard metrics.
 *
 * Depends on:
 * - OrderRepository (data layer) for order data
 * - UserRepository (data layer) for user data
 *
 * Architecture notes:
 * - This service is read-only; it queries existing data and computes aggregations.
 * - Methods return typed analytics models (see src/models/analytics.ts).
 * - Each public method corresponds to one logical API endpoint (see DESIGN.md).
 * - The service does NOT cache results. A future enhancement could add
 *   a caching layer or materialized views for performance.
 *
 * Stub status: Methods return placeholder data. Agents 2-5 will implement
 * the actual aggregation logic against the repositories.
 */

import type { OrderRepository } from '../repositories/order.repository.js';
import type { UserRepository } from '../repositories/user.repository.js';
import type {
  AnalyticsQuery,
  DashboardData,
  MetricQuery,
  MetricSummary,
  MetricType,
  OrderStatusBreakdown,
  TimeSeriesData,
  TopEntity,
} from '../models/analytics.js';
import { Logger } from '../utils/logger.js';

export class AnalyticsService {
  private logger = new Logger('AnalyticsService');

  constructor(
    private orderRepository: OrderRepository,
    private userRepository: UserRepository,
  ) {}

  /**
   * Get the full dashboard payload (all widgets in one call).
   *
   * This is the primary endpoint for the dashboard UI. It combines
   * metrics summaries, time-series charts, status breakdown, and
   * top customers into a single response to minimize round-trips.
   *
   * TODO: Implement aggregation logic using orderRepository and userRepository.
   */
  getDashboard(query: AnalyticsQuery): DashboardData {
    this.logger.info(`Generating dashboard for ${query.startDate} to ${query.endDate}`);

    const granularity = query.granularity ?? 'day';

    return {
      metrics: [
        this.buildMetricSummary('revenue'),
        this.buildMetricSummary('orders'),
        this.buildMetricSummary('users'),
        this.buildMetricSummary('average-order-value'),
      ],
      revenueTimeSeries: this.buildTimeSeriesStub('revenue', query, granularity),
      ordersTimeSeries: this.buildTimeSeriesStub('orders', query, granularity),
      ordersByStatus: this.getOrdersByStatusStub(),
      topCustomers: this.getTopCustomersStub(),
      generatedAt: new Date().toISOString(),
    };
  }

  /**
   * Get a single metric's summary (current vs previous period).
   *
   * Used for individual dashboard cards or detail views.
   *
   * TODO: Implement by querying orders/users within the date range
   * and comparing against the equivalent prior period.
   */
  getMetricSummary(query: MetricQuery): MetricSummary {
    this.logger.info(`Computing metric summary: ${query.metric}`);
    return this.buildMetricSummary(query.metric);
  }

  /**
   * Get time-series data for a specific metric.
   *
   * Used for rendering charts with configurable granularity.
   *
   * TODO: Implement by bucketing orders into time intervals
   * and computing the metric value per bucket.
   */
  getTimeSeries(query: MetricQuery): TimeSeriesData {
    this.logger.info(`Computing time series: ${query.metric}, granularity: ${query.granularity ?? 'day'}`);
    return this.buildTimeSeriesStub(query.metric, query, query.granularity ?? 'day');
  }

  /**
   * Get order counts and totals broken down by status.
   *
   * TODO: Implement by grouping orders from orderRepository.findAll()
   * by status and summing counts/totals.
   */
  getOrdersByStatus(): OrderStatusBreakdown[] {
    this.logger.info('Computing order status breakdown');
    return this.getOrdersByStatusStub();
  }

  /**
   * Get top customers ranked by total revenue.
   *
   * TODO: Implement by joining orders with users, grouping by userId,
   * summing totals, and sorting descending. Limit to top N (default 10).
   */
  getTopCustomers(limit: number = 10): TopEntity[] {
    this.logger.info(`Computing top ${limit} customers`);
    return this.getTopCustomersStub(limit);
  }

  // ── Stub helpers (to be replaced with real aggregation logic) ──

  private buildMetricSummary(metric: MetricType): MetricSummary {
    return {
      metric,
      currentValue: 0,
      previousValue: 0,
      changePercent: 0,
    };
  }

  private buildTimeSeriesStub(
    metric: MetricType,
    query: { startDate: string; endDate: string },
    granularity: string,
  ): TimeSeriesData {
    return {
      metric,
      granularity: granularity as TimeSeriesData['granularity'],
      start: query.startDate,
      end: query.endDate,
      points: [],
    };
  }

  private getOrdersByStatusStub(): OrderStatusBreakdown[] {
    return [
      { status: 'pending', count: 0, total: 0 },
      { status: 'confirmed', count: 0, total: 0 },
      { status: 'shipped', count: 0, total: 0 },
      { status: 'delivered', count: 0, total: 0 },
      { status: 'cancelled', count: 0, total: 0 },
    ];
  }

  private getTopCustomersStub(_limit: number = 10): TopEntity[] {
    return [];
  }
}

/**
 * Analytics service tests.
 *
 * These tests verify the stub/scaffold behavior of the AnalyticsService.
 * As aggregation logic is implemented, these tests should be expanded
 * to verify actual computed values against known test data.
 */

import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { AnalyticsService } from '../../src/services/analytics.service.js';
import type { AnalyticsQuery } from '../../src/models/analytics.js';

describe('AnalyticsService', () => {
  let db: Database;
  let userRepo: UserRepository;
  let orderRepo: OrderRepository;
  let service: AnalyticsService;

  const defaultQuery: AnalyticsQuery = {
    startDate: '2026-01-01T00:00:00Z',
    endDate: '2026-01-31T23:59:59Z',
    granularity: 'day',
  };

  beforeEach(() => {
    db = new Database();
    userRepo = new UserRepository(db);
    orderRepo = new OrderRepository(db);
    service = new AnalyticsService(orderRepo, userRepo);
  });

  describe('getDashboard', () => {
    it('should return a complete dashboard payload', () => {
      const dashboard = service.getDashboard(defaultQuery);

      expect(dashboard.metrics).toHaveLength(4);
      expect(dashboard.metrics.map((m) => m.metric)).toEqual([
        'revenue',
        'orders',
        'users',
        'average-order-value',
      ]);
      expect(dashboard.revenueTimeSeries.metric).toBe('revenue');
      expect(dashboard.ordersTimeSeries.metric).toBe('orders');
      expect(dashboard.ordersByStatus).toHaveLength(5);
      expect(dashboard.topCustomers).toEqual([]);
      expect(dashboard.generatedAt).toBeTruthy();
    });

    it('should default granularity to day', () => {
      const query: AnalyticsQuery = {
        startDate: '2026-01-01T00:00:00Z',
        endDate: '2026-01-31T23:59:59Z',
      };
      const dashboard = service.getDashboard(query);
      expect(dashboard.revenueTimeSeries.granularity).toBe('day');
    });
  });

  describe('getMetricSummary', () => {
    it('should return a metric summary for revenue', () => {
      const summary = service.getMetricSummary({
        metric: 'revenue',
        startDate: defaultQuery.startDate,
        endDate: defaultQuery.endDate,
      });

      expect(summary.metric).toBe('revenue');
      expect(summary.currentValue).toBe(0);
      expect(summary.previousValue).toBe(0);
      expect(summary.changePercent).toBe(0);
    });
  });

  describe('getTimeSeries', () => {
    it('should return time series data with correct metadata', () => {
      const series = service.getTimeSeries({
        metric: 'orders',
        startDate: defaultQuery.startDate,
        endDate: defaultQuery.endDate,
        granularity: 'week',
      });

      expect(series.metric).toBe('orders');
      expect(series.granularity).toBe('week');
      expect(series.start).toBe(defaultQuery.startDate);
      expect(series.end).toBe(defaultQuery.endDate);
      expect(series.points).toEqual([]);
    });
  });

  describe('getOrdersByStatus', () => {
    it('should return all order statuses', () => {
      const breakdown = service.getOrdersByStatus();

      expect(breakdown).toHaveLength(5);
      const statuses = breakdown.map((b) => b.status);
      expect(statuses).toContain('pending');
      expect(statuses).toContain('confirmed');
      expect(statuses).toContain('shipped');
      expect(statuses).toContain('delivered');
      expect(statuses).toContain('cancelled');
    });
  });

  describe('getTopCustomers', () => {
    it('should return empty array in stub', () => {
      const top = service.getTopCustomers(5);
      expect(top).toEqual([]);
    });
  });
});

